import{_ as a,o as r,c as t,ae as s}from"./chunks/framework.oH6zmTcc.js";const o="/atw-rpg/docs/screenshots/player-effective-stats.png",i="/atw-rpg/docs/screenshots/player-season-summary.png",n="/atw-rpg/docs/screenshots/player-career-legacy.png",d="/atw-rpg/docs/screenshots/player-achievements.png",c="/atw-rpg/docs/screenshots/player-season-history.png",b=JSON.parse('{"title":"Player Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/player-dashboard.md","filePath":"guide/player-dashboard.md"}'),h={name:"guide/player-dashboard.md"};function l(m,e,p,u,g,y){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="player-dashboard" tabindex="-1">Player Dashboard <a class="header-anchor" href="#player-dashboard" aria-label="Permalink to &quot;Player Dashboard&quot;">​</a></h1><p>Welcome to the Player Dashboard guide. This documentation is automatically generated from the latest game features.</p><h2 id="effective-stats-and-status-cards" tabindex="-1">Effective Stats and Status Cards <a class="header-anchor" href="#effective-stats-and-status-cards" aria-label="Permalink to &quot;Effective Stats and Status Cards&quot;">​</a></h2><p>The Effective Stats section shows real-time HP, Stamina, Momentum, and Hand Size after applying all active modifiers — campaign bonuses/penalties, injuries, bumps, and Status Cards. Hover over any stat for a full breakdown. Active Status Cards appear as colour-coded badges: green for positive, red for negative.</p><p><img src="'+o+'" alt="Effective Stats and Status Cards"></p><hr><h2 id="season-summary" tabindex="-1">Season Summary <a class="header-anchor" href="#season-summary" aria-label="Permalink to &quot;Season Summary&quot;">​</a></h2><p>The Season Summary component provides a snapshot of your wrestler&#39;s performance during the currently active season, including their win-loss record, fan growth progress, and any championships or accolades earned.</p><p><img src="'+i+'" alt="Season Summary"></p><hr><h2 id="career-legacy" tabindex="-1">Career Legacy <a class="header-anchor" href="#career-legacy" aria-label="Permalink to &quot;Career Legacy&quot;">​</a></h2><p>Your persistent career progress is tracked at the account level. View your current Legacy Score, Prestige XP, and earned achievement badges directly from your dashboard. These stats persist across seasons and different wrestlers.</p><p><img src="'+n+'" alt="Career Legacy"></p><hr><h2 id="medals-achievements" tabindex="-1">Medals &amp; Achievements <a class="header-anchor" href="#medals-achievements" aria-label="Permalink to &quot;Medals &amp; Achievements&quot;">​</a></h2><p>Track your progress toward various career milestones in the Achievements tab. Each achievement awards permanent Prestige XP and a unique medal displayed on your profile.</p><p><img src="'+d+'" alt="Medals &amp; Achievements"></p><hr><h2 id="historical-season-performance" tabindex="-1">Historical Season Performance <a class="header-anchor" href="#historical-season-performance" aria-label="Permalink to &quot;Historical Season Performance&quot;">​</a></h2><p>Review your past glory by switching between seasons. The dashboard stores historical data, allowing you to track your wrestler&#39;s career trajectory and milestones over time.</p><p><img src="'+c+'" alt="Historical Season Performance"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="interactive-promo" tabindex="-1">Interactive Promo <a class="header-anchor" href="#interactive-promo" aria-label="Permalink to &quot;Interactive Promo&quot;">​</a></h3><p>The Silent One responds — AI-generated retort appears under the opponent&#39;s name. The full exchange is persisted to the segment narration and becomes part of the permanent show record, visible to all participants.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/interactive-promo.mp4" type="video/mp4"></video><hr><h3 id="match-narration" tabindex="-1">Match Narration <a class="header-anchor" href="#match-narration" aria-label="Permalink to &quot;Match Narration&quot;">​</a></h3><p>Generate Narration lets the player request an AI-written match story using their deck cards and the segment outcome. Only participants see this button — the result is stored on the segment and visible to everyone afterward.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/player-match-narration.mp4" type="video/mp4"></video><hr><h3 id="navigating-to-a-match" tabindex="-1">Navigating to a Match <a class="header-anchor" href="#navigating-to-a-match" aria-label="Permalink to &quot;Navigating to a Match&quot;">​</a></h3><p>Match view loaded — shows the show name, match type, and participants. Players can submit results, request AI narration, or start an interactive promo depending on the segment type.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/player-go-to-match.mp4" type="video/mp4"></video><hr><h3 id="season-summary-1" tabindex="-1">Season Summary <a class="header-anchor" href="#season-summary-1" aria-label="Permalink to &quot;Season Summary&quot;">​</a></h3><p>Fan growth tracks audience gained or lost this season — wins and title feuds push it up, while losses and inactivity drag it down. The net change is displayed so players can see the impact of their booking outcomes.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/player-season-summary.mp4" type="video/mp4"></video><hr><h3 id="player-dashboard-overview" tabindex="-1">Player Dashboard Overview <a class="header-anchor" href="#player-dashboard-overview" aria-label="Permalink to &quot;Player Dashboard Overview&quot;">​</a></h3><p>Inbox tab — booker messages, angle updates, and match announcements arrive here. Players stay informed about story directions and upcoming bookings without needing to contact the booker directly.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/player-dashboard-overview.mp4" type="video/mp4"></video><hr><h3 id="status-cards-and-momentum" tabindex="-1">Status Cards and Momentum <a class="header-anchor" href="#status-cards-and-momentum" aria-label="Permalink to &quot;Status Cards and Momentum&quot;">​</a></h3><p>Momentum reflects all active status card bonuses — the effective stat shown here is exactly what the match engine uses when drawing cards in combat. Higher momentum increases the chance of landing powerful moves.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/player-status-cards.mp4" type="video/mp4"></video><hr>',47)])])}const f=a(h,[["render",l]]);export{b as __pageData,f as default};
